   return true;
 }

+/// Try to simplify a switch on ucmp/scmp intrinsic.
+/// ucmp/scmp returns -1 (LT), 0 (EQ), or 1 (GT).
+/// When a switch compares against two of these values going to one
+/// destination, we can convert it directly to an icmp.
+static bool simplifySwitchOnCmpIntrinsic(SwitchInst *SI, IRBuilder<> &Builder,
+                                         DomTreeUpdater *DTU) {
+  llvm::errs() << "DEBUG: simplifySwitchOnCmpIntrinsic called\\n";
+  // Only handle switches with exactly 2 cases.
+  if (SI->getNumCases() != 2)
+    return false;
+
+  // Check if the condition is a ucmp/scmp intrinsic.
+  auto *CI = dyn_cast<CmpIntrinsic>(SI->getCondition());
+  if (!CI)
+    return false;
+
+  // Partition the cases into two sets with different destinations.
+  bool HasDefault =
+      !isa<UnreachableInst>(SI->getDefaultDest()->getFirstNonPHIOrDbg());
+  llvm::errs() << "DEBUG: HasDefault=" << HasDefault << "\\n";
+
+  BasicBlock *DestA = HasDefault ? SI->getDefaultDest() : nullptr;
+  BasicBlock *DestB = nullptr;
+  SmallVector<ConstantInt *, 2> CasesA;
+  SmallVector<ConstantInt *, 2> CasesB;
+
+  for (auto Case : SI->cases()) {
+    BasicBlock *Dest = Case.getCaseSuccessor();
+    if (!DestA)
+      DestA = Dest;
+    if (Dest == DestA) {
+      CasesA.push_back(Case.getCaseValue());
+      continue;
+    }
+    if (!DestB)
+      DestB = Dest;
+    if (Dest == DestB) {
+      CasesB.push_back(Case.getCaseValue());
+      continue;
+    }
+    return false; // More than two destinations.
+  }
+
+  if (!DestB)
+    return false;
+
+  assert(DestA && DestB && "Should have two destinations.");
+  assert(DestA != DestB);
+  llvm::errs() << "DEBUG: CasesA.size=" << CasesA.size() << " CasesB.size=" << CasesB.size() << "\\n";
+
+  BasicBlock *BB = SI->getParent();
+
+  // Helper lambdas.
+  auto hasValues = [](ArrayRef<ConstantInt *> Cases, int64_t V1, int64_t V2) {
+    return Cases.size() == 2 &&
+           ((Cases[0]->getValue() == V1 && Cases[1]->getValue() == V2) ||
+            (Cases[0]->getValue() == V2 && Cases[1]->getValue() == V1));
+  };
+  auto hasValue = [](ArrayRef<ConstantInt *> Cases, int64_t V) {
+    return Cases.size() == 1 && Cases[0]->getValue() == V;
+  };
+
+  BasicBlock *TrueDest = nullptr;
+  BasicBlock *FalseDest = nullptr;
+  CmpInst::Predicate Pred;
+
+  // Pattern 1: {-1, 0} -> one dest, {1} -> other dest
+  // This means: if a > b goto Dest with {1} else goto other Dest
+  // When one set is empty, the default dest has the missing value {1}.
+  if ((hasValues(CasesA, -1, 0) && hasValue(CasesB, 1)) ||
+      (hasValues(CasesB, -1, 0) && CasesA.empty())) {
+    Pred = CI->getGTPredicate();
+    TrueDest = DestA;
+    FalseDest = DestB;
+  } else if ((hasValues(CasesB, -1, 0) && hasValue(CasesA, 1)) ||
+             (hasValues(CasesA, -1, 0) && CasesB.empty())) {
+    Pred = CI->getGTPredicate();
+    TrueDest = DestB;
+    FalseDest = DestA;
+  }
+  // Pattern 2: {0, 1} -> one dest, {-1} -> other dest
+  // This means: if a < b goto Dest with {-1} else goto other Dest
+  // When one set is empty, the default dest has the missing value {-1}.
+  else if ((hasValues(CasesA, 0, 1) && hasValue(CasesB, -1)) ||
+           (hasValues(CasesB, 0, 1) && CasesA.empty())) {
+    Pred = CI->getLTPredicate();
+    TrueDest = DestA;
+    FalseDest = DestB;
+  } else if ((hasValues(CasesB, 0, 1) && hasValue(CasesA, -1)) ||
+             (hasValues(CasesA, 0, 1) && CasesB.empty())) {
+    Pred = CI->getLTPredicate();
+    TrueDest = DestB;
+    FalseDest = DestA;
+  }
+  // Pattern 3: {-1, 1} -> one dest, {0} -> other dest
+  // This means: if a != b goto Dest with {-1, 1} else goto Dest with {0}
+  else if (hasValues(CasesA, -1, 1) && hasValue(CasesB, 0)) {
+    Pred = CmpInst::ICMP_NE;
+    TrueDest = DestA;
+    FalseDest = DestB;
+  } else if (hasValues(CasesB, -1, 1) && hasValue(CasesA, 0)) {
+    Pred = CmpInst::ICMP_NE;
+    TrueDest = DestB;
+    FalseDest = DestA;
+  }
+  // No supported pattern found.
+  else {
+    llvm::errs() << "DEBUG: No pattern matched\\n";
+    return false;
+  }
+
+  // Create the comparison.
+  Value *Cmp = Builder.CreateICmp(Pred, CI->getLHS(), CI->getRHS(), "cmp");
+
+  // Create the conditional branch.
+  BranchInst *NewBI = Builder.CreateCondBr(Cmp, TrueDest, FalseDest);
+
+  // Transfer branch weight metadata if present.
+  if (hasBranchWeightMD(*SI)) {
+    SmallVector<uint64_t, 8> Weights;
+    getBranchWeights(SI, Weights);
+    if (Weights.size() == 3) { // default + 2 cases
+      uint64_t TrueWeight = 0;
+      uint64_t FalseWeight = 0;
+      for (size_t I = 0; I < 3; ++I) {
+        BasicBlock *OrigDest = SI->getSuccessor(I);
+        if (OrigDest == TrueDest)
+          TrueWeight += Weights[I];
+        else
+          FalseWeight += Weights[I];
+      }
+      while (TrueWeight > UINT32_MAX || FalseWeight > UINT32_MAX) {
+        TrueWeight /= 2;
+        FalseWeight /= 2;
+      }
+      setBranchWeights(NewBI, TrueWeight, FalseWeight, /*IsExpected=*/false);
+    }
+  }
+
+  // Erase the old switch.
+  if (DTU)
+    DTU->applyUpdates({{DominatorTree::Delete, BB, SI->getDefaultDest()}});
+
+  // Remove the switch from its parent.
+  SI->eraseFromParent();
+
+  return true;
+}
+
 bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
+  llvm::errs() << "DEBUG: simplifySwitch called\\n";
   BasicBlock *BB = SI->getParent();

   if (isValueEqualityComparison(SI)) {
@@ -7163,6 +7313,9 @@ bool SimplifyCFGOpt::simplifySwitch(SwitchInst *SI, IRBuilder<> &Builder) {
   if (eliminateDeadSwitchCases(SI, DTU, Options.AC, DL))
     return requestResimplify();

+  if (simplifySwitchOnCmpIntrinsic(SI, Builder, DTU))
+    return requestResimplify();
+
   if (trySwitchToSelect(SI, Builder, DTU, DL, TTI))
     return requestResimplify();

